#include <stdio.h>
#include <stdbool.h>

bool isPalindrome(int n) {
    int reversed = 0, original = n;
    while (n > 0) {
        reversed = reversed * 10 + n % 10;
        n /= 10;
    }
    return reversed == original;
}

int main() {
    if (isPalindrome(121)) printf("Yes\n");
    return 0;
}
